    console.log(`Cloning ${repo} (${branch})...`);
    child_process.execSync(`git clone ${repoOrg}/${repo} --single-branch -b ${branch} ${dir}`, {
        stdio: 'inherit'
    });
}

function updateRepo(cwd: string) {
    console.log(`Updating ${cwd}...`);
    child_process.execSync('git pull', {
        stdio: 'inherit',
